if (typeof msg.payload === "object") {
    // Extract fields
    const temperature = msg.payload.temperature;
    const humidity = msg.payload.humidity;
    const battery = msg.payload.battery;
    const linkquality = msg.payload.linkquality;
    const voltage = msg.payload.voltage;

    msg.measurement = "LYWSD03MMC";

    msg.payload = [
    {
        topic: msg.topic, 
        temperature: temperature,
